            self$add(jmvcore::Output$new(
                options=options,
                name="rmPredictOV",
                title="Mean predicted values",
                varTitle="RM mean predicted values",
                varDescription="Subject-level mean predicted values from JASP Enhanced Repeated Measures ANOVA",
                measureType="continuous",
                clearWith=list(
                    "repeatedMeasures",
                    "betweenFactors",
                    "covariates")))
            self$add(jmvcore::Html$new(
                options=options,
                name="apa",
                title="APA Reporting",
                visible="(apaReport)"))
            self$add(jmvcore::Html$new(
                options=options,
                name="teaching",
                title="Teaching Mode",
                visible="(teachingMode)"))
            self$add(jmvcore::Html$new(
                options=options,
                name="publication",
                title="Publication Mode",
                visible="(publicationMode)"))
            self$add(jmvcore::Html$new(
                options=options,
                name="reproducibility",
                title="Reproducibility"))
            self$add(jmvcore::Html$new(
                options=options,
                name="about",
                title="About and Citation"))}))

enhancedRepeatedMeasuresAnovaBase <- if (requireNamespace("jmvcore", quietly=TRUE)) R6::R6Class(
    "enhancedRepeatedMeasuresAnovaBase",
    inherit = jmvcore::Analysis,
    public = list(
        initialize = function(options, data=NULL, datasetId="", analysisId="", revision=0) {
            super$initialize(
                package = "jaspEnhancedAnova",
                name = "enhancedRepeatedMeasuresAnova",
                version = c(0,1,0),
                options = options,
                results = enhancedRepeatedMeasuresAnovaResults$new(options=options),
                data = data,
                datasetId = datasetId,
                analysisId = analysisId,
                revision = revision,
                pause = NULL,
                completeWhenFilled = FALSE,
                requiresMissings = FALSE,
                weightsSupport = 'none')
        }))

