    descPlotXAxis,
    descPlotLines,
    descPlotSeparate,
    descPlotError = "ci",
    descPlotYAxisLabel = "",
    descPlotAverageUnused = FALSE,
    barPlots = FALSE,
    barPlotXAxis,
    barPlotSeparate,
    barPlotError = "ci",
    barPlotFixZero = FALSE,
    barPlotYAxisLabel = "",
    barPlotAverageUnused = FALSE,
    raincloudPlots = FALSE,
    raincloudXAxis,
    raincloudSeparate,
    raincloudYAxisLabel = "",
    marginalMeans = FALSE,
    marginalMeanTerms,
    marginalMeansBootstrap = FALSE,
